def _now_str():
    return datetime.utcnow().strftime("%Y-%m-%d %H:%M:%S")

def _expire_str(activated_at, expire_days):
    dt = datetime.strptime(activated_at, "%Y-%m-%d %H:%M:%S")
    return (dt + timedelta(days=expire_days)).strftime("%Y-%m-%d")

def _days_left(activated_at, expire_days):
    expire_dt = datetime.strptime(_expire_str(activated_at, expire_days), "%Y-%m-%d")
    return int((expire_dt - datetime.utcnow()).total_seconds() // 86400)

def _ok(data):
    return json.dumps({"ok": True, **data}, ensure_ascii=False)

def _err(reason):
    return json.dumps({"ok": False, "reason": reason}, ensure_ascii=False)

def do_activate(body):
    key = (body.get("key") or "").strip()
    machine_id = (body.get("machine_id") or "").strip()
    if not key or len(key) != 24:
        return _err("卡密格式错误：应为24位")
    if not machine_id:
        return _err("缺少机器码")

    if key not in licenses:
        return _err("卡密无效，请检查后重新输入")

    doc = licenses[key]
    if doc["used"]:
        if doc["machine_id"] == machine_id:
            remaining = _days_left(doc["activated_at"], doc["expire_days"])
            if remaining < 0:
                return _err(f"此卡密已于 {_expire_str(doc['activated_at'], doc['expire_days'])} 过期")
            return _ok({
                "reason": f"本机已激活，有效期至 {_expire_str(doc['activated_at'], doc['expire_days'])}",
                "activated_at": doc["activated_at"],
                "expire_days": doc["expire_days"],
                "expire_at": _expire_str(doc["activated_at"], doc["expire_days"]),
                "days_left": remaining,
            })
        else:
            return _err("此卡密已在其他设备上使用")

    now_s = _now_str()
    licenses[key] = {"used": True, "machine_id": machine_id, "activated_at": now_s, "expire_days": doc["expire_days"]}
    return _ok({
        "reason": f"激活成功！有效期至 {_expire_str(now_s, doc['expire_days'])}（{doc['expire_days']} 天）",
        "activated_at": now_s,
        "expire_days": doc["expire_days"],
        "expire_at": _expire_str(now_s, doc["expire_days"]),
        "days_left": doc["expire_days"],
    })

def do_check(body):
    key = (body.get("key") or "").strip()
    machine_id = (body.get("machine_id") or "").strip()
    if not key or not machine_id:
        return _err("参数缺失")

    if key not in licenses or not licenses[key]["used"] or licenses[key]["machine_id"] != machine_id:
        return _err("授权记录不存在，请重新激活")

    doc = licenses[key]
    remaining = _days_left(doc["activated_at"], doc["expire_days"])
    if remaining < 0:
        return _err("授权已过期")

    return _ok({
        "days_left": remaining,
        "expire_at": _expire_str(doc["activated_at"], doc["expire_days"]),
        "activated_at": doc["activated_at"],
    })

class handler(BaseHTTPRequestHandler):
    def log_message(self, format, *args):
        pass

    def _send(self, body_str, status=200):
        data = body_str.encode("utf-8")
        self.send_response(status)
        self.send_header("Content-Type", "application/json; charset=utf-8")
        self.end_headers()
        self.wfile.write(data)

    def do_POST(self):
        try:
            length = int(self.headers.get("Content-Length", 0))
            raw = self.rfile.read(length) if length else b"{}"
            body = json.loads(raw or b"{}")
        except:
            self._send(_err("请求体解析失败"), 400)
            return

        action = body.get("action", "")
        try:
            if action == "activate":
                self._send(do_activate(body))
            elif action == "check":
                self._send(do_check(body))
            else:
                self._send(_err(f"未知操作: {action}"), 404)
        except Exception as e:
            import traceback
            self._send(json.dumps({"ok": False, "reason": str(e), "detail": traceback.format_exc()}), 500)

    def do_GET(self):
        self._send(json.dumps({"status": "license-api running", "keys": len(licenses)}))
